CREATE TABLE `exp4_order` (
  `oId` varchar(50) NOT NULL COMMENT '订单号',
  `uId` int(11) unsigned NOT NULL COMMENT '用户ID（严格对齐 exp4_user 的 uid）',
  `total` decimal(10,2) NOT NULL COMMENT '总金额',
  `status` int(2) NOT NULL DEFAULT 0 COMMENT '状态：0待支付，1待发货，2已发货，3待评价，4已评价/已完成，5已取消',
  `orderTime` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '下单时间',
  `shipTime` datetime DEFAULT NULL COMMENT '发货时间',
  `receiverName` varchar(50) DEFAULT NULL COMMENT '收货人姓名',
  `receiverPhone` varchar(20) DEFAULT NULL COMMENT '收货人联系电话',
  `shippingAddress` varchar(250) DEFAULT NULL COMMENT '详细收货地址',
  `originAddress` varchar(100) DEFAULT NULL COMMENT '发货源产地',
  PRIMARY KEY (`oId`),
  INDEX `idx_order_uid` (`uId`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单主表';MariaDB [db23136236]> SHOW CREATE TABLE exp4_order;
